import { CronExpressionParser } from "cron-parser";
import {
  createTaskExtended,
  getDb,
  getDueScheduledTasks,
  getScheduledTaskById,
  updateScheduledTask,
} from "@/be/db";
import type { ScheduledTask } from "@/types";

let schedulerInterval: ReturnType<typeof setInterval> | null = null;
let isProcessing = false;

/**
 * Recover missed scheduled task runs from downtime.
 * Fires ONE catch-up run per schedule (not N missed runs).
 * Tags the task with "recovered" so it's distinguishable.
 */
async function recoverMissedSchedules(): Promise<void> {
  const now = new Date();
  const dueSchedules = getDueScheduledTasks();

  for (const schedule of dueSchedules) {
    if (!schedule.nextRunAt) continue;
    const missedBy = now.getTime() - new Date(schedule.nextRunAt).getTime();
    if (missedBy < 15000) continue; // Less than 15s â€” normal timing jitter

    console.log(
      `[Scheduler] Recovering missed schedule "${schedule.name}" ` +
        `(was due ${Math.round(missedBy / 1000)}s ago)`,
    );

    try {
      const tx = getDb().transaction(() => {
        createTaskExtended(schedule.taskTemplate, {
          creatorAgentId: schedule.createdByAgentId,
          taskType: schedule.taskType,
          tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "recovered"],
          priority: schedule.priority,
          agentId: schedule.targetAgentId,
          model: schedule.model,
          scheduleId: schedule.id,
          source: "schedule",
        });

        const nextRun = calculateNextRun(schedule, now);
        updateScheduledTask(schedule.id, {
          lastRunAt: now.toISOString(),
          nextRunAt: nextRun,
          lastUpdatedAt: now.toISOString(),
        });
      });
      tx();
    } catch (err) {
      console.error(`[Scheduler] Error recovering "${schedule.name}":`, err);
    }
  }
}

/**
 * Calculate next run time based on cron expression or interval.
 * @param schedule The scheduled task
 * @param fromTime The time to calculate from (defaults to now)
 * @returns ISO string of next run time
 */
export function calculateNextRun(schedule: ScheduledTask, fromTime: Date = new Date()): string {
  if (schedule.cronExpression) {
    const interval = CronExpressionParser.parse(schedule.cronExpression, {
      currentDate: fromTime,
      tz: schedule.timezone || "UTC",
    });
    const nextDate = interval.next();
    const isoString = nextDate.toISOString();
    if (!isoString) {
      throw new Error("Failed to calculate next run time from cron expression");
    }
    return isoString;
  }

  if (schedule.intervalMs) {
    return new Date(fromTime.getTime() + schedule.intervalMs).toISOString();
  }

  throw new Error("Schedule must have cronExpression or intervalMs");
}

// Exponential backoff schedule for consecutive errors (in ms)
const ERROR_BACKOFF_MS = [
  60_000, // 1 minute
  300_000, // 5 minutes
  900_000, // 15 minutes
  1_800_000, // 30 minutes
  3_600_000, // 1 hour (cap)
];

const MAX_CONSECUTIVE_ERRORS = 5;

function getBackoffMs(consecutiveErrors: number): number {
  const idx = Math.min(consecutiveErrors - 1, ERROR_BACKOFF_MS.length - 1);
  return ERROR_BACKOFF_MS[Math.max(0, idx)] ?? ERROR_BACKOFF_MS[0]!;
}

/**
 * Execute a single scheduled task by creating an agent task.
 * Tracks consecutive errors and applies exponential backoff on failure.
 */
async function executeSchedule(schedule: ScheduledTask): Promise<void> {
  try {
    const tx = getDb().transaction(() => {
      const now = new Date().toISOString();

      createTaskExtended(schedule.taskTemplate, {
        creatorAgentId: schedule.createdByAgentId,
        taskType: schedule.taskType,
        tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`],
        priority: schedule.priority,
        agentId: schedule.targetAgentId,
        model: schedule.model,
        scheduleId: schedule.id,
        source: "schedule",
      });

      const nextRun = calculateNextRun(schedule, new Date());
      updateScheduledTask(schedule.id, {
        lastRunAt: now,
        nextRunAt: nextRun,
        lastUpdatedAt: now,
        // Reset error tracking on success
        consecutiveErrors: 0,
        lastErrorAt: null,
        lastErrorMessage: null,
      });

      return nextRun;
    });

    const nextRun = tx();
    console.log(`[Scheduler] Executed schedule "${schedule.name}", next run: ${nextRun}`);
  } catch (err) {
    const errorCount = (schedule.consecutiveErrors ?? 0) + 1;
    const now = new Date();
    const errorMsg = err instanceof Error ? err.message : String(err);

    console.error(
      `[Scheduler] Error executing "${schedule.name}" (${errorCount} consecutive):`,
      errorMsg,
    );

    const updates: {
      consecutiveErrors: number;
      lastErrorAt: string;
      lastErrorMessage: string;
      lastUpdatedAt: string;
      enabled?: boolean;
      nextRunAt?: string;
    } = {
      consecutiveErrors: errorCount,
      lastErrorAt: now.toISOString(),
      lastErrorMessage: errorMsg.slice(0, 500),
      lastUpdatedAt: now.toISOString(),
    };

    if (errorCount >= MAX_CONSECUTIVE_ERRORS) {
      updates.enabled = false;
      console.warn(
        `[Scheduler] Auto-disabled "${schedule.name}" after ${errorCount} consecutive errors`,
      );
    } else {
      const backoff = getBackoffMs(errorCount);
      updates.nextRunAt = new Date(now.getTime() + backoff).toISOString();
      console.log(`[Scheduler] Backing off "${schedule.name}" for ${backoff / 1000}s`);
    }

    updateScheduledTask(schedule.id, updates);
  }
}

/**
 * Start the scheduler polling loop.
 * @param intervalMs Polling interval in milliseconds (default: 10000)
 */
export function startScheduler(intervalMs = 10000): void {
  if (schedulerInterval) {
    console.log("[Scheduler] Already running");
    return;
  }

  console.log(`[Scheduler] Starting with ${intervalMs}ms polling interval`);

  // Recover missed schedules from downtime, then run normal processing
  void recoverMissedSchedules().then(() => processSchedules());

  schedulerInterval = setInterval(async () => {
    await processSchedules();
  }, intervalMs);
}

/**
 * Process all due schedules (called by interval).
 */
async function processSchedules(): Promise<void> {
  if (isProcessing) return;
  isProcessing = true;

  try {
    const dueSchedules = getDueScheduledTasks();

    for (const schedule of dueSchedules) {
      try {
        await executeSchedule(schedule);
      } catch (err) {
        console.error(`[Scheduler] Error executing "${schedule.name}":`, err);
      }
    }
  } finally {
    isProcessing = false;
  }
}

/**
 * Stop the scheduler polling loop.
 */
export function stopScheduler(): void {
  if (schedulerInterval) {
    clearInterval(schedulerInterval);
    schedulerInterval = null;
    isProcessing = false;
    console.log("[Scheduler] Stopped");
  }
}

/**
 * Run a schedule immediately (manual trigger).
 * Does NOT update nextRunAt - the regular schedule continues unaffected.
 * @param scheduleId The ID of the schedule to run
 */
export async function runScheduleNow(scheduleId: string): Promise<void> {
  const schedule = getScheduledTaskById(scheduleId);
  if (!schedule) {
    throw new Error(`Schedule not found: ${scheduleId}`);
  }
  if (!schedule.enabled) {
    throw new Error(`Schedule is disabled: ${schedule.name}`);
  }

  // Wrap in transaction to ensure atomicity of task creation and schedule update
  const tx = getDb().transaction(() => {
    const now = new Date().toISOString();

    // Create the actual task
    createTaskExtended(schedule.taskTemplate, {
      creatorAgentId: schedule.createdByAgentId,
      taskType: schedule.taskType,
      tags: [...schedule.tags, "scheduled", `schedule:${schedule.name}`, "manual-run"],
      priority: schedule.priority,
      agentId: schedule.targetAgentId,
      model: schedule.model,
      scheduleId: schedule.id,
      source: "schedule",
    });

    // Only update lastRunAt, not nextRunAt (to not affect regular schedule)
    updateScheduledTask(schedule.id, {
      lastRunAt: now,
      lastUpdatedAt: now,
    });
  });

  tx();

  console.log(`[Scheduler] Manually executed schedule "${schedule.name}"`);
}

import * as z from "zod";

// Task status - includes new unassigned and offered states
export const AgentTaskStatusSchema = z.enum([
  "backlog", // Task is in backlog, not yet ready for pool
  "unassigned", // Task pool - no owner yet
  "offered", // Offered to agent, awaiting accept/reject
  "reviewing", // Agent is reviewing an offered task
  "pending", // Assigned/accepted, waiting to start
  "in_progress",
  "paused", // Interrupted by graceful shutdown, can resume
  "completed",
  "failed",
  "cancelled", // Task was cancelled by lead or creator
]);

// ============================================================================
// Lead Inbox Types
// ============================================================================

export const InboxMessageStatusSchema = z.enum([
  "unread",
  "processing",
  "read",
  "responded",
  "delegated",
]);

export const InboxMessageSchema = z.object({
  id: z.uuid(),
  agentId: z.uuid(), // Lead agent who received this
  content: z.string().min(1), // The message content
  source: z.enum(["slack", "agentmail"]).default("slack"),
  status: InboxMessageStatusSchema.default("unread"),

  // Slack context (for replying)
  slackChannelId: z.string().optional(),
  slackThreadTs: z.string().optional(),
  slackUserId: z.string().optional(),

  // Routing info
  matchedText: z.string().optional(), // Why it was routed here

  // Delegation tracking
  delegatedToTaskId: z.uuid().optional(), // If delegated, which task
  responseText: z.string().optional(), // If responded directly

  // Timestamps
  createdAt: z.iso.datetime(),
  lastUpdatedAt: z.iso.datetime(),
});

export type InboxMessageStatus = z.infer<typeof InboxMessageStatusSchema>;
export type InboxMessage = z.infer<typeof InboxMessageSchema>;

export const AgentTaskSourceSchema = z.enum([
  "mcp",
  "slack",
  "api",
  "github",
  "agentmail",
  "system",
  "schedule",
]);
export type AgentTaskSource = z.infer<typeof AgentTaskSourceSchema>;

export const AgentTaskSchema = z.object({
  id: z.uuid(),
  agentId: z.uuid().nullable(), // Nullable for unassigned tasks
  creatorAgentId: z.uuid().optional(), // Who created this task (optional for Slack/API)
  task: z.string().min(1),
  status: AgentTaskStatusSchema,
  source: AgentTaskSourceSchema.default("mcp"),

  // Task metadata
  taskType: z.string().max(50).optional(), // e.g., "bug", "feature", "chore"
  tags: z.array(z.string()).default([]), // e.g., ["urgent", "frontend"]
  priority: z.number().int().min(0).max(100).default(50),
  dependsOn: z.array(z.uuid()).default([]), // Task IDs this depends on

  // Acceptance tracking
  offeredTo: z.uuid().optional(), // Agent the task was offered to
  offeredAt: z.iso.datetime().optional(),
  acceptedAt: z.iso.datetime().optional(),
  rejectionReason: z.string().optional(),

  // Timestamps
  createdAt: z.iso.datetime().default(() => new Date().toISOString()),
  lastUpdatedAt: z.iso.datetime().default(() => new Date().toISOString()),
  finishedAt: z.iso.datetime().optional(),
  notifiedAt: z.iso.datetime().optional(),

  // Completion data
  failureReason: z.string().optional(),
  output: z.string().optional(),
  progress: z.string().optional(),

  // Slack-specific metadata (optional)
  slackChannelId: z.string().optional(),
  slackThreadTs: z.string().optional(),

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { CronExpressionParser } from "cron-parser";
import * as z from "zod";
import { createScheduledTask, getAgentById, getScheduledTaskByName } from "@/be/db";
import { calculateNextRun } from "@/scheduler";
import { createToolRegistrar } from "@/tools/utils";

export const registerCreateScheduleTool = (server: McpServer) => {
  createToolRegistrar(server)(
    "create-schedule",
    {
      title: "Create Scheduled Task",
      annotations: { destructiveHint: false },
      description:
        "Create a new scheduled task that will automatically create agent tasks at specified intervals. Either cronExpression or intervalMs must be provided.",
      inputSchema: z.object({
        name: z
          .string()
          .min(1)
          .max(100)
          .describe("Unique name for the schedule (e.g., 'daily-cleanup')"),
        taskTemplate: z
          .string()
          .min(1)
          .describe("The task description that will be created each time"),
        cronExpression: z
          .string()
          .optional()
          .describe("Cron expression (e.g., '0 9 * * *' for daily at 9 AM)"),
        intervalMs: z
          .number()
          .int()
          .positive()
          .optional()
          .describe("Interval in milliseconds (e.g., 3600000 for hourly)"),
        description: z.string().optional().describe("Human-readable description of the schedule"),
        taskType: z
          .string()
          .max(50)
          .optional()
          .describe("Task type (e.g., 'maintenance', 'report')"),
        tags: z.array(z.string()).optional().describe("Tags to apply to created tasks"),
        priority: z
          .number()
          .int()
          .min(0)
          .max(100)
          .default(50)
          .optional()
          .describe("Task priority 0-100 (default: 50)"),
        targetAgentId: z
          .string()
          .uuid()
          .optional()
          .describe("Agent to assign tasks to (omit for task pool)"),
        timezone: z.string().default("UTC").optional().describe("Timezone for cron schedules"),
        enabled: z
          .boolean()
          .default(true)
          .optional()
          .describe("Whether the schedule is enabled (default: true)"),
        model: z
          .enum(["haiku", "sonnet", "opus"])
          .optional()
          .describe(
            "Model to use for tasks created by this schedule ('haiku', 'sonnet', or 'opus'). If not set, uses agent/global config or defaults to 'opus'.",
          ),
      }),
      outputSchema: z.object({
        yourAgentId: z.string().uuid().optional(),
        success: z.boolean(),
        message: z.string(),
        schedule: z
          .object({
            id: z.string(),
            name: z.string(),
            description: z.string().optional(),
            cronExpression: z.string().optional(),
            intervalMs: z.number().optional(),
            taskTemplate: z.string(),
            taskType: z.string().optional(),
            tags: z.array(z.string()),
            priority: z.number(),
            targetAgentId: z.string().optional(),
            enabled: z.boolean(),
            lastRunAt: z.string().optional(),
            nextRunAt: z.string().optional(),
            createdByAgentId: z.string().optional(),
            timezone: z.string(),
            model: z.string().optional(),
            createdAt: z.string(),
            lastUpdatedAt: z.string(),
          })
          .optional(),
      }),
    },
    async (
      {
        name,
        taskTemplate,
        cronExpression,
        intervalMs,
        description,
        taskType,
        tags,
        priority,
        targetAgentId,
        timezone,
        enabled,
        model,
      },
      requestInfo,
      _meta,
    ) => {
      if (!requestInfo.agentId) {
        return {
          content: [{ type: "text", text: 'Agent ID not found. Set the "X-Agent-ID" header.' }],
          structuredContent: {
            success: false,
            message: 'Agent ID not found. Set the "X-Agent-ID" header.',
          },
        };
      }

      // Validate that either cronExpression or intervalMs is provided
      if (!cronExpression && !intervalMs) {
        return {
          content: [
            { type: "text", text: "Either cronExpression or intervalMs must be provided." },
          ],
          structuredContent: {
            success: false,
            message: "Either cronExpression or intervalMs must be provided.",
          },
        };
      }

      // Validate cron expression syntax
      if (cronExpression) {
        try {
          CronExpressionParser.parse(cronExpression, { tz: timezone || "UTC" });
        } catch (err) {
          const message = err instanceof Error ? err.message : "Invalid cron expression";
          return {
            content: [{ type: "text", text: `Invalid cron expression: ${message}` }],
            structuredContent: {
              success: false,
              message: `Invalid cron expression: ${message}`,
            },
          };
        }
      }

      // Check for duplicate name
      const existing = getScheduledTaskByName(name);
      if (existing) {
        return {
          content: [{ type: "text", text: `Schedule with name "${name}" already exists.` }],
          structuredContent: {
            success: false,
            message: `Schedule with name "${name}" already exists.`,
          },
        };
      }

      // Validate targetAgentId if provided
      if (targetAgentId) {
        const agent = getAgentById(targetAgentId);
        if (!agent) {
          return {
            content: [{ type: "text", text: `Target agent not found: ${targetAgentId}` }],
            structuredContent: {
              success: false,
              message: `Target agent not found: ${targetAgentId}`,
            },
          };
        }
      }

      try {
        // Calculate initial nextRunAt
        const tempSchedule = {
          cronExpression,
          intervalMs,
          timezone: timezone || "UTC",
        } as Parameters<typeof calculateNextRun>[0];

        const nextRunAt =
          enabled !== false ? calculateNextRun(tempSchedule, new Date()) : undefined;

        const schedule = createScheduledTask({
          name,
          taskTemplate,
          cronExpression,
          intervalMs,
          description,
          taskType,
          tags,
          priority,
          targetAgentId,
          timezone,
          enabled,
          nextRunAt,
          createdByAgentId: requestInfo.agentId,
          model,
        });

        const scheduleType = cronExpression || `every ${intervalMs}ms`;
        return {
          content: [
            {
              type: "text",
              text: `Created schedule "${name}" (${scheduleType}). Next run: ${schedule.nextRunAt || "disabled"}`,
            },
          ],
          structuredContent: {
            yourAgentId: requestInfo.agentId,
            success: true,
            message: `Created schedule "${name}".`,
            schedule,
          },
        };
      } catch (error) {
        const message = error instanceof Error ? error.message : "Unknown error";
        return {
          content: [{ type: "text", text: `Failed to create schedule: ${message}` }],
          structuredContent: {
            yourAgentId: requestInfo.agentId,
            success: false,
            message: `Failed to create schedule: ${message}`,
          },
        };
      }
    },
  );
};

