 13â†’import { calculateNextRun } from "../scheduler/scheduler";
 14â†’import { matchRoute } from "./utils";
 15â†’
 16â†’export async function handleSchedules(
 17â†’  req: IncomingMessage,
 18â†’  res: ServerResponse,
 19â†’  pathSegments: string[],
 20â†’  _queryParams: URLSearchParams,
 21â†’  _myAgentId: string | undefined,
 22â†’): Promise<boolean> {
 23â†’  // POST /api/schedules â€” Create a new schedule
 24â†’  if (matchRoute(req.method, pathSegments, "POST", ["api", "schedules"], true)) {
 25â†’    const chunks: Buffer[] = [];
 26â†’    for await (const chunk of req) {
 27â†’      chunks.push(chunk);
 28â†’    }
 29â†’    const body = JSON.parse(Buffer.concat(chunks).toString());
 30â†’
 31â†’    if (!body.name) {
 32â†’      res.writeHead(400, { "Content-Type": "application/json" });
 33â†’      res.end(JSON.stringify({ error: "Missing required field: name" }));
 34â†’      return true;
 35â†’    }
 36â†’
 37â†’    if (!body.taskTemplate) {
 38â†’      res.writeHead(400, { "Content-Type": "application/json" });
 39â†’      res.end(JSON.stringify({ error: "Missing required field: taskTemplate" }));
 40â†’      return true;
 41â†’    }
 42â†’
 43â†’    // Validate cron expression
 44â†’    if (body.cronExpression) {
 45â†’      try {
 46â†’        CronExpressionParser.parse(body.cronExpression);
 47â†’      } catch {
 48â†’        res.writeHead(400, { "Content-Type": "application/json" });
 49â†’        res.end(JSON.stringify({ error: "Invalid cron expression" }));
 50â†’        return true;
 51â†’      }
 52â†’    }
 53â†’
 54â†’    // Check for duplicate name
 55â†’    const existing = getScheduledTaskByName(body.name);
 56â†’    if (existing) {
 57â†’      res.writeHead(409, { "Content-Type": "application/json" });
 58â†’      res.end(JSON.stringify({ error: "Schedule with this name already exists" }));
 59â†’      return true;
 60â†’    }
 61â†’
 62â†’    // Validate target agent if provided
 63â†’    if (body.targetAgentId) {
 64â†’      const agent = getAgentById(body.targetAgentId);
 65â†’      if (!agent) {
 66â†’        res.writeHead(400, { "Content-Type": "application/json" });
 67â†’        res.end(JSON.stringify({ error: "Target agent not found" }));
 68â†’        return true;
 69â†’      }
 70â†’    }
 71â†’
 72â†’    try {
 73â†’      // Calculate nextRunAt before creation
 74â†’      let nextRunAt: string | undefined;
 75â†’      if (body.enabled !== false) {
 76â†’        const tempSchedule = {
 77â†’          cronExpression: body.cronExpression || null,
 78â†’          intervalMs: body.intervalMs || null,
 79â†’          timezone: body.timezone || "UTC",
 80â†’        };
 81â†’        if (tempSchedule.cronExpression || tempSchedule.intervalMs) {
 82â†’          // biome-ignore lint/suspicious/noExplicitAny: need partial ScheduledTask for calculateNextRun
 83â†’          nextRunAt = calculateNextRun(tempSchedule as any);
 84â†’        }
 85â†’      }
 86â†’
 87â†’      const schedule = createScheduledTask({
 88â†’        name: body.name,
 89â†’        description: body.description,
 90â†’        cronExpression: body.cronExpression,
 91â†’        intervalMs: body.intervalMs,
 92â†’        taskTemplate: body.taskTemplate,
 93â†’        taskType: body.taskType,
 94â†’        tags: body.tags,
 95â†’        priority: body.priority,
 96â†’        targetAgentId: body.targetAgentId,
 97â†’        enabled: body.enabled,
 98â†’        nextRunAt,
 99â†’        timezone: body.timezone,
100â†’        model: body.model,
101â†’      });
102â†’
